@app.route('/enable-mfa', methods=['POST'])
@login_required
@mfa_verified_required
def enable_mfa():
    user_id = session['user_id']
    user = users_db[user_id]

    if user['mfa_enabled']:
        return jsonify({'error': 'MFA is already enabled'}), 400

    # Generate MFA secret
    mfa_secret = pyotp.random_base32()
    totp = pyotp.TOTP(mfa_secret)

    # Generate provisioning URI for QR code
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='MFA Management System'
    )

    # Generate QR code as base64
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    qr_base64 = base64.b64encode(buffer.getvalue()).decode('utf-8')

    # Generate backup codes
    backup_codes = [secrets.token_hex(4).upper() for _ in range(10)]

    # Store temporarily until confirmed
    session['pending_mfa_secret'] = mfa_secret
    session['pending_backup_codes'] = backup_codes

    return jsonify({
        'message': 'Scan the QR code with your authenticator app, then confirm with a TOTP code',
        'mfa_secret': mfa_secret,
        'provisioning_uri': provisioning_uri,
        'qr_code_base64': qr_base64,
        'backup_codes': backup_codes
    }), 200


@app.route('/confirm-mfa', methods=['POST'])
@login_required
@mfa_verified_required
def confirm_mfa():
    user_id = session['user_id']
    user = users_db[user_id]

    if user['mfa_enabled']:
        return jsonify({'error': 'MFA is already enabled'}), 400

    pending_secret = session.get('pending_mfa_secret')
    pending_backup_codes = session.get('pending_backup_codes')

    if not pending_secret:
        return jsonify({'error': 'No pending MFA setup. Call /enable-mfa first'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    totp_code = data.get('totp_code', '').strip()
    if not totp_code:
        return jsonify({'error': 'TOTP code is required to confirm MFA setup'}), 400

    totp = pyotp.TOTP(pending_secret)
    if not totp.verify(totp_code, valid_window=1):
        return jsonify({'error': 'Invalid TOTP code. Please try again'}), 401

    # Activate MFA
    user['mfa_enabled'] = True
    user['mfa_secret'] = pending_secret
    user['mfa_backup_codes'] = pending_backup_codes
    user['updated_at'] = datetime.utcnow().isoformat()

    # Clean up session
    session.pop('pending_mfa_secret', None)
    session.pop('pending_backup_codes', None)

    return jsonify({
        'message': 'MFA has been enabled successfully',
        'backup_codes_remaining': len(user['mfa_backup_codes'])
    }), 200


