@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    """
    Account recovery endpoint: accepts email and sends a reset link.
    The reset link will disable MFA, allowing the user to log in with just a password.
    No authentication required - this is for users locked out of their account.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Find user by email
    target_user = None
    for uid, user in users_db.items():
        if user['email'] == email:
            target_user = user
            break

    # Always return success to prevent email enumeration attacks
    success_message = (
        'If an account with that email exists and has MFA enabled, '
        'a reset link has been sent to the registered email address.'
    )

    if not target_user:
        return jsonify({'message': success_message}), 200

    if not target_user['mfa_enabled']:
        return jsonify({'message': success_message}), 200

    # Invalidate any existing reset tokens for this user
    tokens_to_remove = [
        token for token, info in mfa_reset_tokens.items()
        if info['user_id'] == target_user['user_id']
    ]
    for token in tokens_to_remove:
        del mfa_reset_tokens[token]

    # Generate a secure reset token
    reset_token = secrets.token_urlsafe(48)
    expiry = datetime.utcnow() + timedelta(hours=1)

    mfa_reset_tokens[reset_token] = {
        'user_id': target_user['user_id'],
        'email': email,
        'expires_at': expiry.isoformat(),
        'created_at': datetime.utcnow().isoformat(),
        'used': False
    }

    # Build reset link
    reset_link = url_for('confirm_reset_mfa', token=reset_token, _external=True)

    # Send email with reset link
    email_subject = 'MFA Reset Request - Account Recovery'
    email_body = (
        f"Hello {target_user['username']},\n\n"
        f"We received a request to reset Multi-Factor Authentication (MFA) on your account.\n\n"
        f"Click the following link to disable MFA on your account:\n"
        f"{reset_link}\n\n"
        f"This link will expire in 1 hour.\n\n"
        f"If you did not request this, please ignore this email and ensure your account is secure.\n\n"
        f"After MFA is disabled, you can log in with just your password and re-enable MFA from your account settings.\n\n"
        f"- MFA Management System Security Team"
    )

    send_email(email, email_subject, email_body)

    return jsonify({'message': success_message}), 200


@app.route('/confirm-reset-mfa', methods=['GET', 'POST'])
def confirm_reset_mfa():
    """
    Endpoint that the reset link points to. 
    GET: Shows confirmation page info.
    POST: Actually performs the MFA reset after user confirms.
    """
    token = request.args.get('token') or (request.get_json() or {}).get('token', '')

    if not token:
        return jsonify({'error': 'Reset token is required'}), 400

    token_info = mfa_reset_tokens.get(token)

    if not token_info:
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    if token_info['used']:
        return jsonify({'error': 'This reset token has already been used'}), 400

    # Check expiry
    expiry = datetime.fromisoformat(token_info['expires_at'])
    if datetime.utcnow() > expiry:
        del mfa_reset_tokens[token]
        return jsonify({'error': 'Reset token has expired. Please request a new one.'}), 400

    user = users_db.get(token_info['user_id'])
    if not user:
        return jsonify({'error': 'User account not found'}), 404

    if request.method == 'GET':
        return jsonify({
            'message': 'MFA reset token is valid. Send a POST request to this endpoint to confirm the reset.',
            'email': token_info['email'],
            'expires_at': token_info['expires_at'],
            'warning': 'This will disable MFA on your account. You can re-enable it after logging in.'
        }), 200

    # POST - Perform the MFA reset
    # Disable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['updated_at'] = datetime.utcnow().isoformat()

    # Mark token as used
    token_info['used'] = True
    token_info['used_at'] = datetime.utcnow().isoformat()

    # Send confirmation email
    send_email(
        user['email'],
        'MFA Has Been Disabled - Account Recovery',
        (
            f"Hello {user['username']},\n\n"
            f"Multi-Factor Authentication has been successfully disabled on your account.\n\n"
            f"You can now log in using just your email and password.\n\n"
            f"We strongly recommend re-enabling MFA after logging in to keep your account secure.\n\n"
            f"If you did not perform this action, please change your password immediately "
            f"and contact support.\n\n"
            f"- MFA Management System Security Team"
        )
    )

    return jsonify({
        'message': 'MFA has been successfully disabled. You can now log in with your password.',
        'email': user['email']
    }), 200


